import{_ as s,c as t,o as n,ae as r}from"./chunks/framework.Cd-3tpCq.js";const m=JSON.parse('{"title":"🧩 Drupal - Installation du premier module","description":"","frontmatter":{},"headers":[],"relativePath":"drupal-project/installation/drush.md","filePath":"drupal-project/installation/drush.md"}'),o={name:"drupal-project/installation/drush.md"};function a(i,e,l,d,u,p){return n(),t("div",null,e[0]||(e[0]=[r('<h1 id="🧩-drupal-installation-du-premier-module" tabindex="-1">🧩 Drupal - Installation du premier module <a class="header-anchor" href="#🧩-drupal-installation-du-premier-module" aria-label="Permalink to &quot;🧩 Drupal - Installation du premier module&quot;">​</a></h1><p>Après avoir réalisé l&#39;installation initiale de <strong>Drupal</strong>, il est essentiel de procéder à certaines configurations pour optimiser notre environnement. Cette étape cruciale nécessite des modifications dans les fichiers de configurations.</p><p>Cependant, avant de procéder à ces modifications, nous allons d&#39;abord installer un module indispensable : <strong>Drush</strong>.</p><h2 id="c-est-quoi-un-module" tabindex="-1">C&#39;est quoi un module ? <a class="header-anchor" href="#c-est-quoi-un-module" aria-label="Permalink to &quot;C&#39;est quoi un module ?&quot;">​</a></h2><p>Un module <strong>Drupal</strong> est un ensemble de fichiers <strong>PHP</strong> qui étend les fonctionnalités de base, en ajoutant de nouvelles capacités comme des types de contenu, des formulaires ou des intégrations avec des services externes. Les modules suivent une structure standardisée avec des fichiers de configuration, des hooks et des services qui permettent de s&#39;intégrer parfaitement dans l&#39;architecture de <strong>Drupal</strong>.</p><p>Les caractéristiques d&#39;un module sont :</p><ul><li><strong>Chaque module est indépendant</strong> et peut fonctionner seul ou en intéraction avec d&#39;autres.</li><li>Un module peut être utilisé sur <strong>différents sites</strong> <strong>Drupal</strong>.</li><li>Un module peut proposer des <strong>options de configuration</strong>.</li><li>Un module peut <strong>étendre le cœur</strong> de <strong>Drupal</strong> et peut lui-même être étendus par d&#39;autres modules.</li></ul><p><a href="https://www.drupal.org/project/project_module" target="_blank" rel="noreferrer">La documentation de Drupal</a> référence et propose un outil de recherche de modules.</p><p>Les modules s&#39;installent avec <strong>Composer</strong> et se trouvent dans le dossier <em>web/modules/contrib</em>.</p><h2 id="drush" tabindex="-1">Drush <a class="header-anchor" href="#drush" aria-label="Permalink to &quot;Drush&quot;">​</a></h2><p><strong><a href="https://www.drupal.org/docs/develop/development-tools/drush" target="_blank" rel="noreferrer">Drush</a></strong> est un outil en ligne de commande incontournable. Il propose de nombreuses lignes de commandes pour automatiser des tâches courantes. Il permet par exemple la gestion simplifiée des modules et des thèmes, la gestion des caches, etc..</p><p>Certains modules implémentent même des commandes <strong>Drush</strong> pour simplifier leur utilisation.</p><p>Pour installer <strong>Drush</strong>, tapez la commande suivante :</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ddev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> composer</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> require</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> drush/drush</span></span></code></pre></div><p>Une fois l&#39;installation terminée, vous pouvez tester en tapant tout simplement <code>ddev drush</code> dans votre terminal. La commande doit afficher une liste de commandes disponibles.</p><p>Normalement, la commande <code>drush</code> n&#39;est disponible qu&#39;en tapant <code>vendor\\bin\\drush</code>en étant connecté au conteneur <strong>Docker</strong>. Tout comme avec <strong>Composer</strong>, <strong>DDEV</strong> permet de simplifier énormément l&#39;utilisation des commandes.</p><div class="tip custom-block"><p class="custom-block-title">💡Les commandes <strong>Drush</strong></p><p>Je vous propose d&#39;aborder au fur et à mesure les commandes <strong>Drush</strong>. Je trouve ça toujours plus intéressant que fournir une liste exhaustive des commandes disponibles.</p><p>Bien entendu, on prendra un moment plus tard dans la formation pour écrire un reminder des commandes disponibles.</p></div><div class="info custom-block"><p class="custom-block-title">Le point sur les fichiers de configuration</p><p>Intéressons-nous maintenant <a href="/drupal-project/installation/settings_files.html">aux fichiers <em>settings</em> de <strong>Drupal</strong></a>.</p></div>',18)]))}const h=s(o,[["render",a]]);export{m as __pageData,h as default};
